### Instruction:
Design a function to count the number of unique characters in a string.

### Response:
def count_unique_chars(string):
  char_dict = {}
  for char in string:
    if char in char_dict:
      char_dict[char] += 1
    else:
      char_dict[char] = 1
  return len(char_dict)

print(count_unique_chars("Butterflies"))
# Output: 9

### Instruction:
Write a Python function that takes two integers and returns their least common multiple.

### Response:
def lcm(a, b):
  if a > b:
    greater = a
  else:
    greater = b
  while(True):
    if((greater % a == 0) and (greater % b == 0)):
      lcm = greater
      break
    greater += 1
  return lcm

print(lcm(15, 18))
# Output: 90
